import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./mentorDashboard.css";

export default function MentorDashboard() {
  const [mentor, setMentor] = useState(null);
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    if (!token) {
      navigate("/login");
      return;
    }
    const load = async () => {
      try {
        const res = await axios.get("http://localhost:5050/api/mentors/me", {
          headers: { Authorization: `Bearer ${token}` }
        });
        setMentor(res.data);
      } catch (err) {
        console.error("Error loading mentor data:", err);
        if (err.response?.status === 401 || err.response?.status === 403) {
          localStorage.clear();
          navigate("/login");
        }
      }
    };
    load();
  }, [token, navigate]);

  if (!mentor) return <p>Loading...</p>;

  return (
    <div className="mentor-dashboard">
      <div className="dashboard-header">
        <h1>Welcome, {mentor.facultyname}</h1>
        <button onClick={() => { localStorage.clear(); navigate("/login"); }}>Logout</button>
      </div>
      <p><strong>Specialization:</strong> {mentor.specialization}</p>
      <p><strong>Email:</strong> {mentor.Email}</p>
    </div>
  );
}
